section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/error-handling-in-vui.json",
  "title": "Error Handling in VUI",
  "type": "object",
  "required": [
    "artefact_id",
    "intent_id",
    "ladder_steps",
    "retry_budget",
    "bailout_route",
    "telemetry_events",
    "fallback_copy",
    "human_handoff",
    "tested_on",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "intent_id": {
      "type": "string",
      "description": "intent_id",
      "minLength": 1
    },
    "ladder_steps": {
      "type": "array",
      "description": "ladder_steps (array)",
      "minItems": 1
    },
    "retry_budget": {
      "type": "string",
      "description": "retry_budget",
      "minLength": 1
    },
    "bailout_route": {
      "type": "string",
      "description": "bailout_route",
      "minLength": 1
    },
    "telemetry_events": {
      "type": "array",
      "description": "telemetry_events (array)",
      "minItems": 1
    },
    "fallback_copy": {
      "type": "string",
      "description": "fallback_copy",
      "minLength": 1
    },
    "human_handoff": {
      "type": "array",
      "description": "human_handoff (array)",
      "minItems": 1
    },
    "tested_on": {
      "type": "string",
      "description": "tested_on",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
